// PerTopicScore Per-topic correct/total breakdown for an attempt. Canonical definition; ScoreEvent references this same shape.
type PerTopicScore struct {
	// Correct Number of correctly answered questions for this topic.
	Correct int `json:"correct"`

	// TopicId The topic these counts belong to.
	TopicId string `json:"topicId"`

	// Total Total number of questions for this topic in the attempt.
	Total int `json:"total"`
}

// Problem RFC 7807-style problem detail returned for any error response. The HTTP status of the response matches the `status` field and the `code` category.
type Problem struct {
	// Code Machine-readable error category. Maps to the matching HTTP status: VALIDATION->422/400, NOT_FOUND->404, UNAUTHORIZED->401, CONFLICT->409, INTERNAL->500.
	Code Code `json:"code"`

	// Detail A human-readable explanation specific to this occurrence.
	Detail *string `json:"detail,omitempty"`

	// Status The HTTP status code for this occurrence of the problem.
	Status int `json:"status"`

	// Title A short, human-readable summary of the problem type.
	Title string `json:"title"`

	// Type A URI reference identifying the problem type. May be the literal "about:blank" when no specific type is defined.
	Type string `json:"type"`
}

// Progress A student's progress summary: per-topic mastery, the current streak, and recent attempt history.
type Progress struct {
	// History Recent exam attempts, newest first.
	History []ExamAttempt `json:"history"`

	// Mastery Per-topic mastery levels (0–100).
	Mastery []TopicMastery `json:"mastery"`

	// Streak Current consecutive-pass streak (in days).
	Streak int `json:"streak"`

	// StudentId The student this progress belongs to.
	StudentId string `json:"studentId"`
}

// Question A multiple-choice question with its answer key. This is the parent-facing (authoring) shape; the student receives DeliveredQuestion, which omits correctOptionId.
type Question struct {
	// CorrectOptionId The id of the option that is correct (must match an option's id).
	CorrectOptionId string `json:"correctOptionId"`

	// Difficulty Relative difficulty of a question.
	Difficulty Difficulty `json:"difficulty"`

	// Enabled Whether this question is eligible for selection into exams.
	Enabled bool `json:"enabled"`

	// Id Unique question identifier.
	Id string `json:"id"`

	// Options The answer options. At least four are required.
	Options []Option `json:"options"`

	// SubjectId Subject this question belongs to.
	SubjectId string `json:"subjectId"`

	// Text The question prompt.
	Text string `json:"text"`

	// TopicId Optional topic this question is scoped to.
	TopicId *string `json:"topicId,omitempty"`
}

// QuestionDraft An AI-generated multiple-choice question awaiting parent review. Mirrors the CreateQuestion authoring shape (options as plain texts plus a correctOptionIndex) so that approving a draft maps cleanly onto a real Question (C05). A draft has status pending until a parent approves (creates a Question) or rejects it.
type QuestionDraft struct {
	// CorrectOptionIndex Zero-based index into options identifying the correct answer.
	CorrectOptionIndex int `json:"correctOptionIndex"`

	// Difficulty Relative difficulty of a question.
	Difficulty Difficulty `json:"difficulty"`

	// Id Server-assigned unique identifier for this draft.
	Id string `json:"id"`

	// Options The candidate answer options. At least four are required.
	Options []QuestionDraftOption `json:"options"`

	// Status Review status of the draft.
	Status QuestionDraftStatus `json:"status"`

	// SubjectId Subject this draft belongs to.
	SubjectId string `json:"subjectId"`

	// Text The question prompt.
	Text string `json:"text"`

	// TopicId Optional topic this draft is scoped to.
	TopicId *string `json:"topicId,omitempty"`
}

// QuestionDraftStatus Review status of the draft.
type QuestionDraftStatus string

// QuestionDraftOption A candidate answer option on a generated draft. Plain text only; no id is assigned until the draft is approved into a Question.
type QuestionDraftOption struct {
	// Text The option's display text.
	Text string `json:"text"`
}

// RewardStyle How earned internet time relates to the score. `flat` grants the full time for the exam size on a pass; `scaled` multiplies by the score%.
type RewardStyle string

// ScoreEvent Immutable record of a single graded exam outcome. Emitted by Phase 1 on exam submission and consumed only by the Phase 3 Guardian. Carries the score and per-topic breakdown but no reward/minutes/time fields, which are Guardian-only.
type ScoreEvent struct {
	// AttemptId ID of the ExamAttempt (C06) this score came from.
	AttemptId string `json:"attemptId"`

	// ExamDefinitionId ID of the ExamDefinition (C04) that produced the attempt.
	ExamDefinitionId string `json:"examDefinitionId"`

	// Passed Whether the attempt met the exam's pass bar.
	Passed bool `json:"passed"`

	// PerTopic Per-topic correct/total breakdown for the attempt.
	PerTopic []PerTopicScore `json:"perTopic"`

	// ScopeTopicIds Topic IDs the exam was scoped to. Empty array means the whole subject (mirrors ExamDefinition.scopeTopicIds).
	ScopeTopicIds []string `json:"scopeTopicIds"`

	// ScorePct Final score as a whole percentage (0–100).
	ScorePct int `json:"scorePct"`

	// Size Number of questions in the attempt.
	Size int `json:"size"`

	// StudentId ID of the Student (C07) who took the exam.
	StudentId string `json:"studentId"`

	// SubjectId ID of the Subject (C01) the exam belongs to.
	SubjectId string `json:"subjectId"`

	// Timestamp RFC 3339 timestamp of when the score was recorded.
	Timestamp time.Time `json:"timestamp"`
}

// Session The active session identity returned after a successful auth ceremony. Mirrors what the server stores behind the sr_session cookie.
type Session struct {
	// Id Id of the authenticated parent or student.
	Id string `json:"id"`

	// Role Whether the session belongs to a parent or a student.
	Role SessionRole `json:"role"`
}

// SessionRole Whether the session belongs to a parent or a student.
type SessionRole string

// Settings The application settings singleton. Holds the spec defaults that gate exam creation plus the Guardian-side reward knobs (stored now, used in Phase 3). L10 ResolveSettings fills any missing field from these same defaults at runtime.
type Settings struct {
	// DailyCapHours Guardian-side: maximum hours of earned time per day. Stored now, unused until Phase 3.
	DailyCapHours int `json:"dailyCapHours"`

	// DefaultCooldownMin Default cooldown (minutes) after a failed attempt.
	DefaultCooldownMin int `json:"defaultCooldownMin"`

	// DefaultExamSize Default number of questions for a new exam definition.
	DefaultExamSize int `json:"defaultExamSize"`

	// DefaultPassBar Default pass threshold (percent) for a new exam definition.
	DefaultPassBar int `json:"defaultPassBar"`

	// DifficultyRamp Whether exam assembly ramps difficulty (easy -> hard) across the delivered questions.
	DifficultyRamp bool `json:"difficultyRamp"`

	// Id Identifier of the settings singleton row.
	Id string `json:"id"`

	// KnowledgeBackend The selected knowledge backend.
	KnowledgeBackend KnowledgeBackend `json:"knowledgeBackend"`

	// RewardRateMinPerQ Guardian-side: minutes of earned time per correct question. Stored now, unused until Phase 3.
	RewardRateMinPerQ int `json:"rewardRateMinPerQ"`
}

// Source A study source attached to a subject.
type Source struct {
	// CreatedAt RFC 3339 creation timestamp.
	CreatedAt time.Time `json:"createdAt"`

	// FileRef Storage reference for a `file` source (set only for files).
	FileRef *string `json:"fileRef,omitempty"`

	// Id Unique source id (UUID/cuid).
	Id string `json:"id"`

	// Status Processing state of a source. Phase 1 sources are created `ready`; `processing` is reserved for Phase 2 async ingestion/OCR.
	Status SourceStatus `json:"status"`

	// SubjectId Id of the subject this source belongs to.
	SubjectId string `json:"subjectId"`

	// Text Inline content for a `text` source.
	Text *string `json:"text,omitempty"`

	// Title Human-readable title for the source.
	Title string `json:"title"`

	// Type The kind of study source.
	Type SourceType `json:"type"`

	// Url URL for a `notebooklm` source.
	Url *string `json:"url,omitempty"`
}

// SourceStatus Processing state of a source. Phase 1 sources are created `ready`; `processing` is reserved for Phase 2 async ingestion/OCR.
type SourceStatus string

// SourceType The kind of study source.
